    for (const auto& shapePtr : shapes) {
        std::cout << "Area: " << shapePtr->calculateArea() << std::endl;
    }

    // Clean up dynamically allocated memory
    for (const auto& shapePtr : shapes) {
        delete shapePtr;
    }
    shapes.clear();

    return 0;
